var ecricpFunction = (function () {
    let featureId = 3; // for clipboard paste text

    function savePasteData(destinationId, pastedData, module, ecriCpId) {
        let response = {data: []};
        $.ajax({
            url: "/mobiledoc/clinicaldocumentation/ecricopypaste/setecripastedata",
            type: "POST",
            async: true,
            data: $.param({
                destinationId: destinationId,
                pastedData: pastedData,
                module: module,
                featureId: 3,
                ecriCpId: ecriCpId,
                modality: "web"
            }),
            success: function (data) {
                response = data;
            },
            error: function (data) {
                response = data;
            }
        });
        return response;
    }

    function savePnPasteData(pastedText, ecriCpId) {
        let extRefId, module;
        if(typeof currentGlobalContext !== 'undefined'){
            if (currentGlobalContext === "PN_DASHBOARD" && document.getElementById('pnController') && angular.element(document.getElementById('pnController')) && angular.element(document.getElementById('pnController')).scope()) {
                extRefId = angular.element(document.getElementById('pnController')).scope().encounterId;
                module = "PN";
            }
        }else if (ecriCPContext && ecriCPContext.module === "webClickThrough"){
            extRefId =  ecriCPContext.encounterId;
            module = "PN";
        }
        savePasteData(extRefId, pastedText, module, ecriCpId);
    }

    var emrPasteEventHandler = function (e) {
        if(typeof e !== 'undefined') {
            var pastedText;
            var element;
            if (e.target) {
                    element = e.target;
            }else if(e.editor && e.editor.element){
                element = e.editor.element;
            } else if (e.e && e.e.textarea && e.e.textarea.element) {
                element = e.e.textarea.element;
            }

            if (element) {
                let ecriCpId = element.getAttribute("ecri-cp-id");
                if (ecriCpId) {
                    if (e.originalEvent && e.originalEvent.clipboardData && e.originalEvent.clipboardData.getData) { // IE
                        pastedText = e.originalEvent.clipboardData.getData('Text');
                    } else if (e.clipboardData && e.clipboardData.getData) {
                        pastedText = e.clipboardData.getData('text/plain');
                    } else if (e.data && e.data.dataValue) {
                        pastedText = htmlToText(e.data.dataValue);
                    }
                    if(pastedText) {
                        savePnPasteData(pastedText.trim(), ecriCpId);
                    } else if (typeof e.promise !== 'undefined') {
                        setTimeout(function () {
                            e.promise.then(function (text) {
                                savePnPasteData(text.trim(), ecriCpId);
                            });
                        }, 1000);
                    }
                }
            }
        }
    };

    function htmlToText(html) {
        var temp = document.createElement('div');
        temp.innerHTML = html;
        return temp.textContent; // Or return temp.innerText if you need to return only visible text. It's slower.
    }

    ecricpFunction.emrPasteEventHandler = emrPasteEventHandler;
});
ecricpFunction();
$(document).bind("paste", ecricpFunction.emrPasteEventHandler);

